mapper.select:
/* KtPlcyMgmtMapper.getKtPlcyList */
SELECT A.PLCY_ID AS plcyId ,A.SLS_NO AS slsNo ,A.SLS_NM AS slsNm ,A.PLCY_TYPE AS plcyType ,FN_GET_CODENM('ORG0073', A.PLCY_TYPE) AS plcyTypeNm ,A.PPPO AS pppo ,FN_GET_CODENM('RCP0013', A.PPPO) AS pppoNm ,A.USE_YN AS useYn ,FN_GET_CODENM('CMN0011', A.USE_YN) AS useYnNm ,FN_GET_USRNM(A.REGST_ID) AS regstId ,TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm FROM MSP_KT_PLCY_MST A WHERE 1 = 1
AND A.USE_YN = #{useYn, jdbcType=VARCHAR}
AND A.PLCY_TYPE = #{plcyType, jdbcType=VARCHAR}
AND A.PPPO = #{pppo, jdbcType=VARCHAR}
AND A.SLS_NM LIKE '%'||#{slsNm, jdbcType=VARCHAR}||'%'
ORDER BY A.USE_YN DESC, A.PLCY_TYPE DESC, A.PPPO, A.RVISN_DTTM DESC

mapper.insert:

	SELECT TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(TO_NUMBER(NVL(SUBSTR(MAX(PLCY_ID), 9), '00')) + 1, '00')) AS plcyId
	FROM   MSP_KT_PLCY_MST
	WHERE  SUBSTR(PLCY_ID, 1, 8) = TO_CHAR(SYSDATE, 'YYYYMMDD')

/* KtPlcyMgmtMapper.regMspKtPlcyMst */
INSERT INTO MSP_KT_PLCY_MST (
	PLCY_ID
	,SLS_NO
	,SLS_NM
	,PLCY_TYPE
	,PPPO
	,USE_YN
	,REGST_ID
	,REGST_DTTM
	,RVISN_ID
	,RVISN_DTTM
) VALUES (
	 #{plcyId}
	,#{slsNo}
	,#{slsNm}
	,#{plcyType}
	,#{pppo}
	,#{useYn}
	,#{sessionUserId}
	,SYSDATE
	,#{sessionUserId}
	,SYSDATE
)

