mapper.update:

	SELECT TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(TO_NUMBER(NVL(SUBSTR(MAX(PLCY_ID), 9), '00')) + 1, '00')) AS plcyId
	FROM   MSP_KT_PLCY_MST
	WHERE  SUBSTR(PLCY_ID, 1, 8) = TO_CHAR(SYSDATE, 'YYYYMMDD')

/* KtPlcyMgmtMapper.updMspKtPlcyMst */
UPDATE MSP_KT_PLCY_MST
SET 
	PLCY_ID = #{plcyId}
	,SLS_NM = #{slsNm}
	,PLCY_TYPE = #{plcyType}
	,PPPO = #{pppo}
	,USE_YN = #{useYn}
	,RVISN_ID = #{sessionUserId}
	,RVISN_DTTM = SYSDATE
WHERE SLS_NO = #{slsNo}

mapper.select:
/* KtPlcyMgmtMapper.getKtPlcyListCombo */ SELECT '[' || A.SLS_NO || ']'|| A.SLS_NM AS text ,A.SLS_NO AS value FROM MSP_KT_PLCY_MST A ,MSP_KT_PLCY_DISCOUNT B ,MSP_KT_PLCY_OPER C ,MSP_KT_PLCY_INST D ,MSP_KT_PLCY_ENGG E WHERE 1 = 1
AND A.USE_YN = #{useYn}
AND A.PPPO = #{pppo} AND A.PLCY_ID = B.PLCY_ID AND A.SLS_NO = B.SLS_NO AND A.PLCY_ID = C.PLCY_ID AND A.SLS_NO = C.SLS_NO AND A.PLCY_ID = D.PLCY_ID AND A.SLS_NO = D.SLS_NO AND A.PLCY_ID = E.PLCY_ID AND A.SLS_NO = E.SLS_NO AND A.PLCY_TYPE = DECODE(#{plcyType},'MM','01','UU','02',#{plcyType}) --01 : 단말, 02 : USIM AND B.DC_TYPE = NVL(#{dcType},'NN') AND C.OPER_TYPE = #{operType} AND D.INST_CNT = #{instCnt} AND E.ENGG_CNT = #{enggCnt} ORDER BY A.RVISN_DTTM DESC
